from dataclasses import dataclass

@dataclass
class Rectangle:
    """A rectangle with float width and height."""
    width: float
    height: float

def area(rect: Rectangle) -> float:
    """Calculate the area of a rectangle."""
    return rect.width * rect.height

def perimeter(rect: Rectangle) -> float:
    """Calculate the perimeter of a rectangle."""
    return 2 * (rect.width + rect.height)

def scale(rect: Rectangle, factor: float) -> Rectangle:
    """Return a new rectangle scaled by a factor."""
    return Rectangle(rect.width * factor, rect.height * factor)

# Usage
if __name__ == "__main__":
    rect = Rectangle(3.0, 4.0)

    print(area(rect))
    print(perimeter(rect))

    scaled_rect = scale(rect, 2.0)
    print(area(scaled_rect))
